<?php
declare(strict_types=1);

function sf_vp3_bridge_request(string $endpoint,array $payload,string $method='POST',?string $requestId=null):array{
 $settings=sf_vp3_clip_settings();if(empty($settings['api_base'])||empty($settings['bridge_uuid'])||empty($settings['bridge_secret']))return['ok'=>false,'error'=>'bridge_not_configured'];if(!function_exists('curl_init'))return['ok'=>false,'error'=>'curl_unavailable'];$url=rtrim((string)$settings['api_base'],'/').'/'.ltrim($endpoint,'/');$raw=json_encode($payload,JSON_UNESCAPED_SLASHES|JSON_THROW_ON_ERROR);$timestamp=(string)time();$nonce=rtrim(strtr(base64_encode(random_bytes(24)),'+/','-_'),'=');$requestId=$requestId&&preg_match('/^[0-9a-f-]{36}$/i',$requestId)?$requestId:sf_vp3_clip_uuid();$path=(string)(parse_url($url,PHP_URL_PATH)?:'/');$canonical=strtoupper($method)."\n".$path."\n".$timestamp."\n".$nonce."\n".hash('sha256',$raw);$signature=hash_hmac('sha256',$canonical,(string)$settings['bridge_secret']);$headers=['Content-Type: application/json','Accept: application/json','X-VP3-Bridge-ID: '.$settings['bridge_uuid'],'X-VP3-Timestamp: '.$timestamp,'X-VP3-Nonce: '.$nonce,'X-VP3-Request-ID: '.$requestId,'X-VP3-Signature: '.$signature];$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_CUSTOMREQUEST=>$method,CURLOPT_POSTFIELDS=>$raw,CURLOPT_HTTPHEADER=>$headers,CURLOPT_RETURNTRANSFER=>true,CURLOPT_FOLLOWLOCATION=>false,CURLOPT_CONNECTTIMEOUT=>15,CURLOPT_TIMEOUT=>90,CURLOPT_SSL_VERIFYPEER=>true,CURLOPT_SSL_VERIFYHOST=>2]);$body=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);$error=curl_error($ch);curl_close($ch);$decoded=is_string($body)?json_decode($body,true):null;if(!is_array($decoded)||empty($decoded['ok']))return['ok'=>false,'error'=>(string)($decoded['error']['code']??$error?:'vp3_request_failed'),'status'=>$status,'request_uuid'=>$requestId,'response'=>is_array($decoded)?$decoded:null];return['ok'=>true,'status'=>$status,'request_uuid'=>$requestId,'data'=>$decoded['data']??[]];}
function sf_vp3_clip_context():array{return sf_vp3_bridge_request('api/v1/clips/bridge/context.php',[]);}
function sf_vp3_clip_publish(int $id,?string $requestId=null):array{$pdo=sf_db();$clip=sf_vp3_clip_by_id($id);if(!$pdo||!$clip)return['ok'=>false,'error'=>'clip_not_found'];if($clip['local_status']==='failed'||!is_file((string)$clip['rendered_video_path'])||!is_file((string)$clip['rendered_poster_path']))return['ok'=>false,'error'=>'rendered_clip_required'];if(empty($clip['rights_confirmed']))return['ok'=>false,'error'=>'rights_confirmation_required'];$settings=sf_vp3_clip_settings();$payload=['contract_version'=>'1.0','source_clip_uuid'=>$clip['clip_uuid'],'source_creator_uuid'=>$settings['source_creator_uuid']??'','source_show_uuid'=>$settings['source_show_uuid']??'','title'=>$clip['title'],'caption'=>$clip['caption'],'media_type'=>'video','source_media_url'=>sf_vp3_clip_public_url($clip,'video'),'poster_url'=>sf_vp3_clip_public_url($clip,'poster'),'destination_url'=>$clip['destination_url'],'duration_seconds'=>(int)$clip['duration_seconds'],'aspect_ratio'=>$clip['aspect_ratio'],'visibility'=>'public','feed_eligible'=>true,'rights_confirmed'=>true,'rights_owner_name'=>$clip['rights_owner_name'],'rights_expires_at'=>$clip['rights_expires_at'],'scheduled_at'=>$clip['scheduled_at'],'source_updated_at'=>date(DATE_ATOM,strtotime((string)$clip['source_updated_at']))];$pdo->prepare("UPDATE vp3_clips SET local_status='publishing',last_error=NULL WHERE id=?")->execute([$id]);$result=sf_vp3_bridge_request('api/v1/clips/bridge/publications.php',$payload,$clip['central_publication_uuid']?'PUT':'POST',$requestId);sf_vp3_clip_apply_response($id,$result,'publish');return$result;}
function sf_vp3_clip_sync(int $id):array{$clip=sf_vp3_clip_by_id($id);if(!$clip)return['ok'=>false,'error'=>'clip_not_found'];$result=sf_vp3_bridge_request('api/v1/clips/bridge/status.php',['source_clip_uuid'=>$clip['clip_uuid']]);sf_vp3_clip_apply_response($id,$result,'status');if(!empty($result['ok'])){$analytics=sf_vp3_bridge_request('api/v1/clips/bridge/analytics.php',['source_clip_uuid'=>$clip['clip_uuid']]);if(!empty($analytics['ok'])){sf_db()->prepare('UPDATE vp3_clips SET central_analytics_json=?,last_synced_at=NOW() WHERE id=?')->execute([json_encode($analytics['data'],JSON_UNESCAPED_SLASHES),$id]);}return['ok'=>true,'status'=>$result['data'],'analytics'=>$analytics['data']??null];}return$result;}
function sf_vp3_clip_withdraw(int $id):array{$clip=sf_vp3_clip_by_id($id);if(!$clip)return['ok'=>false,'error'=>'clip_not_found'];$result=sf_vp3_bridge_request('api/v1/clips/bridge/publications.php',['source_clip_uuid'=>$clip['clip_uuid']],'DELETE');sf_vp3_clip_apply_response($id,$result,'withdraw');return$result;}
function sf_vp3_clip_apply_response(int $id,array $result,string $event):void{$pdo=sf_db();if(!$pdo)return;if(empty($result['ok'])){$pdo->prepare("UPDATE vp3_clips SET local_status=IF(local_status IN ('published','scheduled','pending','ready'),'held','failed'),last_error=?,last_synced_at=NOW() WHERE id=?")->execute([substr((string)($result['error']??'vp3_request_failed'),0,1000),$id]);sf_vp3_clip_event($id,null,$event,'failed',(int)($result['status']??0),$result);return;}$d=(array)($result['data']??[]);$pub=(string)($d['publication_status']??'pending');$local=match($pub){'published'=>'published','scheduled'=>'scheduled','withdrawn'=>'withdrawn','suspended'=>'held',default=>'pending'};$pdo->prepare('UPDATE vp3_clips SET central_publication_uuid=COALESCE(?,central_publication_uuid),central_publication_status=?,central_moderation_status=?,central_rights_status=?,central_feed_eligible=?,local_status=?,last_error=NULL,last_synced_at=NOW() WHERE id=?')->execute([$d['publication_uuid']??null,$pub,$d['moderation_status']??null,$d['rights_status']??null,!empty($d['feed_eligible'])?1:0,$local,$id]);sf_vp3_clip_event($id,null,$event,'success',(int)($result['status']??200),['request_uuid'=>$result['request_uuid']??null,'data'=>$d]);}
function sf_vp3_clip_event(int $clipId,?int $jobId,string $type,string $status,?int $httpStatus,array $metadata=[]):void{$pdo=sf_db();if(!$pdo||!sf_vp3_clip_tables_ready())return;$pdo->prepare('INSERT INTO vp3_clip_sync_events (clip_id,job_id,event_type,event_status,request_uuid,http_status,metadata_json) VALUES (?,?,?,?,?,?,?)')->execute([$clipId,$jobId,$type,$status,$metadata['request_uuid']??null,$httpStatus,$metadata?json_encode($metadata,JSON_UNESCAPED_SLASHES):null]);}
